(70, 1, '2026-02-07 12:46:13', '2026-02-07 12:46:13', '<!-- wp:group {\"metadata\":{\"name\":\"Hero\"},\"align\":\"full\",\"className\":\"nfd-container nfd-wb-hero__hero-29\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignfull nfd-container nfd-wb-hero__hero-29\"><!-- wp:cover {\"url\":\"https://ofa.bwy.mybluehost.me/website_4704f9a4/wp-content/uploads/2026/02/photo-1642132652860-603f4e3c19b7.jpg\",\"dimRatio\":50,\"overlayColor\":\"black\",\"isUserOverlayColor\":true,\"minHeight\":656,\"minHeightUnit\":\"px\",\"contentPosition\":\"center center\",\"sizeSlug\":\"full\",\"className\":\"alignfull\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"-28px\"}}}} -->\n<div class=\"wp-block-cover alignfull\" style=\"margin-top:-28px;min-height:656px\"><img class=\"wp-block-cover__image-background size-full\" alt=\"\" src=\"https://ofa.bwy.mybluehost.me/website_4704f9a4/wp-content/uploads/2026/02/photo-1642132652860-603f4e3c19b7.jpg\" data-object-fit=\"cover\"/><span aria-hidden=\"true\" class=\"wp-block-cover__background has-black-background-color has-background-dim\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:group {\"className\":\"alignfull is-style-default nfd-gap-lg nfd-p-lg\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\",\"flexWrap\":\"nowrap\"}} -->\n<div class=\"wp-block-group alignfull is-style-default nfd-gap-lg nfd-p-lg\"><!-- wp:spacer {\"height\":\"0px\",\"className\":\"nfd-my-0\",\"style\":{\"layout\":{\"selfStretch\":\"fixed\",\"flexSize\":\"150px\"}}} -->\n<div style=\"height:0px\" aria-hidden=\"true\" class=\"wp-block-spacer nfd-my-0\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|accent-2\"}}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"200\"}},\"textColor\":\"accent-2\",\"fontSize\":\"medium\"} -->\n<p class=\"has-accent-2-color has-text-color has-link-color has-medium-font-size\" style=\"font-style:normal;font-weight:200\">October 15, 2023</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":1,\"className\":\"nfd-text-current nfd-text-giga md:nfd-text-left md:nfd-no-br\",\"fontSize\":\"xx-large\"} -->\n<h1 class=\"wp-block-heading has-text-align-center nfd-text-current nfd-text-giga md:nfd-text-left md:nfd-no-br has-xx-large-font-size\">Streamline Your Divorce Process</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"nfd-text-balance md:nfd-text-left\",\"fontSize\":\"medium\"} -->\n<p class=\"has-text-align-center nfd-text-balance md:nfd-text-left has-medium-font-size\">Experience a hassle-free divorce with our AI-driven solutions. We provide quick and easy access to all necessary legal documents and support for your case.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"style\":{\"spacing\":{\"blockGap\":\"40px\",\"margin\":{\"top\":\"24px\"}}},\"layout\":{\"type\":\"flex\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-buttons\" style=\"margin-top:24px\"><!-- wp:button {\"className\":\"is-style-fill\",\"style\":{\"typography\":{\"textTransform\":\"uppercase\"}}} -->\n<div class=\"wp-block-button is-style-fill\"><a class=\"wp-block-button__link wp-element-button\" href=\"#\" style=\"text-transform:uppercase\">Get Started Today</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->\n\n<!-- wp:spacer {\"height\":\"0px\",\"className\":\"nfd-my-0\",\"style\":{\"layout\":{\"selfStretch\":\"fixed\",\"flexSize\":\"50px\"}}} -->\n<div style=\"height:0px\" aria-hidden=\"true\" class=\"wp-block-spacer nfd-my-0\"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:group --></div></div>\n<!-- /wp:cover --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"metadata\":{\"name\":\"Gallery\"},\"className\":\"nfd-container nfd-wb-gallery__gallery-28\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group nfd-container nfd-wb-gallery__gallery-28\"><!-- wp:group {\"layout\":{\"type\":\"grid\",\"minimumColumnWidth\":\"17rem\"}} -->\n<div class=\"wp-block-group\"><!-- wp:cover {\"url\":\"https://ofa.bwy.mybluehost.me/website_4704f9a4/wp-content/uploads/2026/02/photo-1556894181-cb8e4ccca5d0.jpg\",\"dimRatio\":0,\"isUserOverlayColor\":true,\"sizeSlug\":\"full\",\"style\":{\"dimensions\":{\"aspectRatio\":\"1\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-cover\"><img class=\"wp-block-cover__image-background size-full\" alt=\"\" src=\"https://ofa.bwy.mybluehost.me/website_4704f9a4/wp-content/uploads/2026/02/photo-1556894181-cb8e4ccca5d0.jpg\" data-object-fit=\"cover\"/><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim-0 has-background-dim\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:paragraph {\"align\":\"center\",\"placeholder\":\"Write title…\",\"fontSize\":\"large\"} -->\n<p class=\"has-text-align-center has-large-font-size\"></p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:cover -->\n\n<!-- wp:cover {\"url\":\"https://ofa.bwy.mybluehost.me/website_4704f9a4/wp-content/uploads/2026/02/photo-1642132652860-603f4e3c19b7-1.jpg\",\"dimRatio\":0,\"isUserOverlayColor\":true,\"contentPosition\":\"top center\",\"sizeSlug\":\"large\",\"style\":{\"layout\":{\"rowSpan\":2}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-cover has-custom-content-position is-position-top-center\"><img class=\"wp-block-cover__image-background size-large\" alt=\"\" src=\"https://ofa.bwy.mybluehost.me/website_4704f9a4/wp-content/uploads/2026/02/photo-1642132652860-603f4e3c19b7-1.jpg\" data-object-fit=\"cover\"/><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim-0 has-background-dim\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:group {\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\"}} -->\n<div class=\"wp-block-group\"><!-- wp:group {\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\"}} -->\n<div class=\"wp-block-group