(77, 4, 'fvp_yoast_notifications', 'a:2:{i:0;a:2:{s:7:\"message\";s:290:\"<p>Because of a change in your home URL setting, some of your SEO data needs to be reprocessed. We estimate this will take less than a minute.</p><a class=\"button\" href=\"http://legaldivorcedocs.local/wp-admin/admin.php?page=wpseo_tools&start-indexation=true\">Start SEO data optimization</a>\";s:7:\"options\";a:11:{s:4:\"type\";s:7:\"warning\";s:2:\"id\";s:13:\"wpseo-reindex\";s:7:\"user_id\";i:4;s:5:\"nonce\";N;s:8:\"priority\";d:0.8;s:9:\"data_json\";a:0:{}s:13:\"dismissal_key\";N;s:12:\"capabilities\";s:20:\"wpseo_manage_options\";s:16:\"capability_check\";s:3:\"all\";s:14:\"yoast_branding\";b:0;s:13:\"resolve_nonce\";s:0:\"\";}}i:1;a:2:{s:7:\"message\";s:454:\"Your recent posts are using default SEO titles and meta descriptions, which can make them easy to overlook in search results. Update them for better visibility or <a href=\"https://yoa.st/ai-generate-alert-free/?php_version=8.3&#038;platform=wordpress&#038;platform_version=6.9.1&#038;software=free&#038;software_version=26.9&#038;days_active=4&#038;user_language=en_US\" target=\"_blank\">try <strong>Yoast AI Generate</strong> for free to do it faster.</a>\";s:7:\"options\";a:11:{s:4:\"type\";s:7:\"warning\";s:2:\"id\";s:22:\"wpseo-default-seo-data\";s:7:\"user_id\";i:4;s:5:\"nonce\";N;s:8:\"priority\";d:0.5;s:9:\"data_json\";a:0:{}s:13:\"dismissal_key\";N;s:12:\"capabilities\";a:1:{i:0;s:20:\"wpseo_manage_options\";}s:16:\"capability_check\";s:3:\"all\";s:14:\"yoast_branding\";b:0;s:13:\"resolve_nonce\";s:0:\"\";}}}'),
